/// <summary>
/// Extension of the <c>AgreementConfirmationDP</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(AgreementConfirmationDP))]
public final class AgreementConfirmationDP_ETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Method to populate the <c>AgreementHeaderTmp</c> table
/// from the <c>AgreementHeaderHistory</c> table.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
private void ETGSPAINgetAgreementHeaderHistory(AgreementHeaderTmp  _agreementHeaderTmp)
{
    AgreementHeaderHistory  agreementHeaderHistory;

    select firstonly agreementHeaderHistory
        where agreementHeaderHistory.RecId == recId;

    _agreementHeaderTmp.ETGSPAINPurchExecutionDueDate                = agreementHeaderHistory.ETGSPAINPurchExecutionDueDate;
    _agreementHeaderTmp.ETGSPAINPurchExecutionFromDate               = agreementHeaderHistory.ETGSPAINPurchExecutionFromDate;
    _agreementHeaderTmp.ETGSPAINCreationDate                         = agreementHeaderHistory.ETGSPAINCreationDate;
    _agreementHeaderTmp.ETGSPAINSalesVendGroup                       = agreementHeaderHistory.ETGSPAINSalesVendGroup;
    _agreementHeaderTmp.ETGSPAINPurchPlateDaysNumber                 = agreementHeaderHistory.ETGSPAINPurchPlateDaysNumber;
    _agreementHeaderTmp.ETGSPAINDefaultAgreementLineEffectiveDate    = agreementHeaderHistory.ETGSPAINDefaultAgreementLineEffectiveDate;
    _agreementHeaderTmp.ETGSPAINPurchIntermediary                    = agreementHeaderHistory.ETGSPAINPurchIntermediary;
    _agreementHeaderTmp.ETGSPAINPaymTermsDescription                 = agreementHeaderHistory.ETGSPAINPaymTermsDescription;
    _agreementHeaderTmp.ETGSPAINUnloadCity                           = agreementHeaderHistory.ETGSPAINUnloadCity;
    _agreementHeaderTmp.ETGSPAINLoadCity                             = agreementHeaderHistory.ETGSPAINLoadCity;
}

/// <summary>
/// Extension of the <c>getPurchAgreementHeaderHistory</c> method.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
internal void getPurchAgreementHeaderHistory(AgreementHeaderTmp  _agreementHeaderTmp)
{
    next getPurchAgreementHeaderHistory(_agreementHeaderTmp);

    this.ETGSPAINgetAgreementHeaderHistory(_agreementHeaderTmp);

    PurchAgreementHeaderHistory         purchAgreementHeaderHistory;
    PurchAgreementHeaderDefaultHistory  purchAgreementHeaderDefaultHistory;

    select purchAgreementHeaderHistory
        where purchAgreementHeaderHistory.RecId                                         == recId
            join purchAgreementHeaderDefaultHistory
                where purchAgreementHeaderDefaultHistory.PurchaseAgreementHeaderHistory == purchAgreementHeaderHistory.RecId;

    VendPaymModeTable   vendPaymModeTable = VendPaymModeTable::findByCompany(purchAgreementHeaderDefaultHistory.MethodOfPaymentDataAreaId,
                                                                                purchAgreementHeaderDefaultHistory.MethodOfPayment);

    _agreementHeaderTmp.ETGSPAINMethodOfPayment                      = purchAgreementHeaderDefaultHistory.MethodOfPayment;
    _agreementHeaderTmp.ETGSPAINPaymModeName                         = vendPaymModeTable.Name;

}

/// <summary>
/// Extension of the <c>getSalesAgreementHeaderHistory</c> method.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
internal void getSalesAgreementHeaderHistory(AgreementHeaderTmp  _agreementHeaderTmp)
{
    next getSalesAgreementHeaderHistory(_agreementHeaderTmp);

    this.ETGSPAINgetAgreementHeaderHistory(_agreementHeaderTmp);

    SalesAgreementHeaderHistory         salesAgreementHeaderHistory;
    SalesAgreementHeaderDefaultHistory  salesAgreementHeaderDefaultHistory;

    select salesAgreementHeaderHistory
        where salesAgreementHeaderHistory.RecId                                         == recId
            join salesAgreementHeaderDefaultHistory
                where salesAgreementHeaderDefaultHistory.SalesAgreementHeaderHistory    == salesAgreementHeaderHistory.RecId;

    CustPaymModeTable   custPaymModeTable = CustPaymModeTable::findByCompany(salesAgreementHeaderDefaultHistory.CustomerMethodOfPaymentDataAreaId,
                                                                                salesAgreementHeaderDefaultHistory.CustomerMethodOfPayment);

    _agreementHeaderTmp.ETGSPAINMethodOfPayment      = salesAgreementHeaderDefaultHistory.CustomerMethodOfPayment;
    _agreementHeaderTmp.ETGSPAINPaymModeName         = custPaymModeTable.Name;
}

/// <summary>
/// Method to populate the <c>AgreementHeaderTmp</c> table
/// from the <c>AgreementHeader</c> table.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
private void ETGSPAINgetAgreementHeader(AgreementHeaderTmp  _agreementHeaderTmp)
{
    AgreementHeader             agreementHeader;

    select firstonly agreementHeader
        where agreementHeader.RecId == recId;

    _agreementHeaderTmp.ETGSPAINDefaultAgreementLineEffectiveDate   = agreementHeader.DefaultAgreementLineEffectiveDate;
    _agreementHeaderTmp.ETGSPAINCreationDate                        = DateTimeUtil::date(agreementHeader.CreatedDateTime);
    _agreementHeaderTmp.ETGSPAINPurchExecutionDueDate               = agreementHeader.ETGSPAINPurchExecutionDueDate;
    _agreementHeaderTmp.ETGSPAINPurchExecutionFromDate              = agreementHeader.ETGSPAINPurchExecutionFromDate;
    _agreementHeaderTmp.ETGSPAINPurchPlateDaysNumber                = agreementHeader.ETGSPAINPurchPlateDaysNumber;
    _agreementHeaderTmp.ETGSPAINDefaultAgreementLineEffectiveDate   = agreementHeader.DefaultAgreementLineEffectiveDate;

    AgreementLine           agreementLine;
    ETGSPAINPurchLoadPortTable   ETGSPAINPurchLoadPortTable;
    ETGSPAINPurchUnloadPortTable ETGSPAINPurchUnloadPortTable;

    select firstonly agreementLine
        order by ETGSPAINPurchLoadPortId desc
        where agreementLine.Agreement                       == agreementHeader.RecId
            outer join ETGSPAINPurchLoadPortTable
                where ETGSPAINPurchLoadPortTable.LoadPortId      == agreementLine.ETGSPAINPurchLoadPortId;

    _agreementHeaderTmp.ETGSPAINLoadCity                            = ETGSPAINPurchLoadPortTable.AdressCity;

    select firstonly agreementLine
        order by ETGSPAINPurchUnloadPortId desc
        where agreementLine.Agreement                       == agreementHeader.RecId
            outer join ETGSPAINPurchUnloadPortTable
                where ETGSPAINPurchUnloadPortTable.UnloadPortId  == agreementLine.ETGSPAINPurchUnloadPortId;

    _agreementHeaderTmp.ETGSPAINUnloadCity                          = ETGSPAINPurchUnloadPortTable.AdressCity;
}

/// <summary>
/// Extension of the <c>getPurchAgreementHeader</c> method.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
internal void getPurchAgreementHeader(AgreementHeaderTmp  _agreementHeaderTmp)
{
    next getPurchAgreementHeader(_agreementHeaderTmp);

    this.ETGSPAINgetAgreementHeader(_agreementHeaderTmp);

    PurchAgreementHeader        purchAgreementHeader = PurchAgreementHeader::find(recId);
    PurchAgreementHeaderDefault purchAgreementHeaderDefault = PurchAgreementHeaderDefault::findPurchAgreementHeader(purchAgreementHeader.RecId);
    HcmWorker                   HcmWorker = HcmWorker::find(purchAgreementHeader.PrimaryResponsibleWorker);


    _agreementHeaderTmp.ETGSPAINSalesVendGroup                       = purchAgreementHeader.vendTable().VendGroup;
    _agreementHeaderTmp.ETGSPAINMethodOfPayment                      = purchAgreementHeaderDefault.MethodOfPayment;
    _agreementHeaderTmp.ETGSPAINPurchIntermediary                    = HcmWorker.name();

    AgreementHeaderDefault  agreementHeaderDefault = purchAgreementHeader.agreementHeaderDefault();
    PaymTerm                paymTerm;

    select firstonly paymTerm
            where paymTerm.DataAreaId == agreementHeaderDefault.PaymentTermsDataAreaId
                && paymTerm.PaymTermId == agreementHeaderDefault.PaymentTerms;

    _agreementHeaderTmp.ETGSPAINPaymTermsDescription                 = paymTerm.Description;

    _agreementHeaderTmp.ETGSPAINPaymModeName                         = VendPaymModeTable::findByCompany(purchAgreementHeaderDefault.MethodOfPaymentDataAreaId,
                                                                                purchAgreementHeaderDefault.MethodOfPayment).Name;
}

/// <summary>
/// Extension of the <c>getSalesAgreementHeader</c> method.
/// </summary>
/// <param name="_agreementHeaderTmp">Instance of <c>AgreementHeaderTmp</c></param>
internal void getSalesAgreementHeader(AgreementHeaderTmp  _agreementHeaderTmp)
{
    next getSalesAgreementHeader(_agreementHeaderTmp);

    this.ETGSPAINgetAgreementHeader(_agreementHeaderTmp);

    SalesAgreementHeader salesAgreementHeader = SalesAgreementHeader::find(recId);

    SalesAgreementHeaderDefault salesAgreementHeaderDefault = SalesAgreementHeaderDefault::findSalesAgreementHeader(recId);

    _agreementHeaderTmp.ETGSPAINSalesVendGroup      = salesAgreementHeader.custTable().CustGroup;
    _agreementHeaderTmp.ETGSPAINMethodOfPayment     = salesAgreementHeaderDefault.CustomerMethodOfPayment;
    _agreementHeaderTmp.ETGSPAINPurchIntermediary   = salesAgreementHeaderDefault.CommissionSalesGroup;

    AgreementHeaderDefault  agreementHeaderDefault = salesAgreementHeader.agreementHeaderDefault();
    PaymTerm                paymTerm;

    select firstonly paymTerm
            where paymTerm.DataAreaId == agreementHeaderDefault.PaymentTermsDataAreaId
                && paymTerm.PaymTermId == agreementHeaderDefault.PaymentTerms;

    _agreementHeaderTmp.ETGSPAINPaymTermsDescription                 = paymTerm.Description;

    _agreementHeaderTmp.ETGSPAINPaymModeName                         = CustPaymModeTable::findByCompany(salesAgreementHeaderDefault.CustomerMethodOfPaymentDataAreaId,
                                                                                salesAgreementHeaderDefault.CustomerMethodOfPayment).Name;
}

/// <summary>
/// Extension of the <c>initializeQuantityCommitmentHistoryAgreementLine</c> method.
/// </summary>
/// <param name="_parameters">Parameters for line history creation</param>
protected void initializeQuantityCommitmentHistoryAgreementLine(AgreementConfirmationDPLineHistoryCreationParameters _parameters)
{
    next initializeQuantityCommitmentHistoryAgreementLine(_parameters);

    AgreementLineHistory agreementLineHistory = _parameters.agreementLineQuantityCommitmentHistory;

    agreementLineTmp.ETGSPAINPurchExecutionDueDate           = agreementLineHistory.ETGSPAINPurchExecutionDueDate;
    agreementLineTmp.ETGSPAINPurchExecutionFromDate          = agreementLineHistory.ETGSPAINPurchExecutionFromDate;
    agreementLineTmp.ETGSPAINPurchSalesAgreementLinecode     = agreementLineHistory.ETGSPAINPurchSalesAgreementLinecode;
    agreementLineTmp.ETGSPAINItemTextPrintoutOfAgreements    = agreementLineHistory.ETGSPAINItemTextPrintoutOfAgreements;
    agreementLineTmp.ETGSPAINLineCode                        = agreementLineHistory.ETGSPAINLineCode;
}

/// <summary>
/// Extension of the <c>initializeQuantityCommitmentAgreementLine</c> method.
/// </summary>
/// <param name="_parameters">Parameters for line creation</param>
protected void initializeQuantityCommitmentAgreementLine(AgreementConfirmationDPLineCreationParameters _parameters)
{
    next initializeQuantityCommitmentAgreementLine(_parameters);

    AgreementLine agreementLine = AgreementLine::find(_parameters.agreementLineQuantityCommitment.RecId);

    agreementLineTmp.ETGSPAINPurchExecutionDueDate           = agreementLine.ETGSPAINPurchExecutionDueDate;
    agreementLineTmp.ETGSPAINPurchExecutionFromDate          = agreementLine.ETGSPAINPurchExecutionFromDate;
    agreementLineTmp.ETGSPAINItemTextPrintoutOfAgreements    = agreementLine.inventTable().ETGSPAINItemTextPrintoutOfAgreements;;
    agreementLineTmp.ETGSPAINLineCode                        = agreementLine.ETGSPAINLineCode;
    agreementLineTmp.ETGSPAINPurchSalesAgreementLinecode     = agreementLine.ETGSPAINLineCode;
}
